<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    kwargs = </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">dict</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">do_sample</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">False</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span>
